import './DropdownItem.scss';

import { Typography } from ':components/Typography';
import type { FC, ReactNode } from 'react';
import React from 'react';

import { classNames } from '../../../helpers/classnames';
import type { DropdownItemProps } from '../Dropdown.types';

const renderText = (content: ReactNode, variant: 'body2' | 'body3', ellipsis = false, inactive = false): ReactNode => {
	if (typeof content === 'string') {
		return (
			<Typography variant={variant} ellipsis={ellipsis} inactive={inactive}>
				{content}
			</Typography>
		);
	}

	return content;
};

export const DropdownItem: FC<DropdownItemProps> = ({
	label,
	description,
	startAdornment,
	suffix,
	selected = false,
	focused = false,
	disabled = false,
	children,
	className,
	dataTestId = 'DropdownItem',
	onClick,
	...props
}) => {
	const rootClassName = classNames(
		'dsb_dropdown-item',
		{
			'dsb_dropdown-item--selected': selected,
			'dsb_dropdown-item--focused': focused,
			'dsb_dropdown-item--disabled': disabled,
		},
		className,
	);

	const handleClick = (event: React.MouseEvent<HTMLDivElement>): void => {
		if (disabled) {
			return;
		}
		onClick?.(event);
	};

	const handleKeyDown = (event: React.KeyboardEvent<HTMLDivElement>): void => {
		if (disabled) {
			return;
		}
		if (event.key === 'Enter' || event.key === ' ') {
			event.preventDefault();
			onClick?.(event as unknown as React.MouseEvent<HTMLDivElement>);
		}
	};

	return (
		<div
			className={rootClassName}
			data-testid={dataTestId}
			role="option"
			aria-selected={selected}
			aria-disabled={disabled}
			tabIndex={disabled ? -1 : 0}
			onClick={handleClick}
			onKeyDown={handleKeyDown}
			{...props}
		>
			{children ?? (
				<>
					{startAdornment && <div className="dsb_dropdown-item__start">{startAdornment}</div>}
					<div className="dsb_dropdown-item__content">
						{label && <div className="dsb_dropdown-item__label">{renderText(label, 'body2', true)}</div>}
						{description && (
							<div className="dsb_dropdown-item__description">{renderText(description, 'body3', true, true)}</div>
						)}
					</div>
					{suffix && <div className="dsb_dropdown-item__suffix">{renderText(suffix, 'body3', false, true)}</div>}
				</>
			)}
		</div>
	);
};
